def mean_reciprocal_rank(relevance_lists: list[list[int]]) -> float:
    rrs = []
    for rel in relevance_lists:
        rr = 0.0
        for rank, r in enumerate(rel, 1):
            if r == 1:
                rr = 1.0 / rank
                break
        rrs.append(rr)
    return sum(rrs) / len(rrs) if rrs else 0.0
